B.a4a=s(["export","download","backup","JSON","data","GDPR"],t.s)
B.aUn=new A.bR("Export My Data","Download all your stocks and journal entries as a JSON file.","Go to Settings \u2192 Export My Data.\n\nThe export includes:\n\u2022 All stocks (owned, watching, sold)\n\u2022 All transactions per stock\n\u2022 All journal entries\n\nFormat: JSON (readable by any text editor or spreadsheet app).\n\nUse this to back up your data or migrate to another tool.",null,B.a4a)
B.a4x=s(["delete","account","remove","GDPR","right to erasure","close account"],t.s)
B.aUe=new A.bR("Delete Account","Permanently deletes all your data and your account. Cannot be undone.","Go to Settings \u2192 Danger Zone \u2192 Delete My Account.\n\nType DELETE to confirm.\n\nThis permanently removes:\n\u2022 All stocks and transactions\n\u2022 All journal entries\n\u2022 All snapshots\n\u2022 Your login credentials\n\n\u26a0 There is no undo. Export your data first if you want to keep a copy.",null,B.a4x)
B.a1H=s(["journal","notes","diary","log","write","record"],t.s)
B.aUG=new A.bR("Journal","Attach notes, thoughts, and records to individual stocks.","Open any stock \u2192 tap the Journal button.\n\nUse the journal to:\n\u2022 Record why you bought or sold\n\u2022 Log news or events affecting the stock\n\u2022 Track your investment thesis over time\n\u2022 Note your emotional state at the time (useful for behaviour analysis)\n\nEntries are stored per stock and included in the data export.",null,B.a1H)
B.a1c=s(["share","certificate","social","milestone","image"],t.s)
B.aUF=new A.bR("Share Certificate","Generate a visual certificate for a stock position to share.","Open a stock detail screen \u2192 tap Share Certificate.\n\nGenerates a stylised image showing:\n\u2022 Stock name and symbol\n\u2022 Number of shares held\n\u2022 Your average purchase price\n\u2022 Current value\n\nUseful for sharing investment milestones on social media.",null,B.a1c)
